import sql from "@/app/api/utils/sql";
import { hash } from "argon2";

export async function POST(request) {
  try {
    const body = await request.json().catch(() => ({}));
    const token = String(body?.token || "").trim();
    const password = String(body?.password || "");

    if (!token || !password) {
      return Response.json(
        { error: "Token and password are required" },
        { status: 400 },
      );
    }

    if (password.trim().length < 8) {
      return Response.json(
        { error: "Password must be at least 8 characters" },
        { status: 400 },
      );
    }

    const rows = await sql(
      `
        SELECT token, user_id
        FROM password_reset_tokens
        WHERE token = $1
          AND used = false
          AND expires_at > now()
        LIMIT 1
      `,
      [token],
    );

    const reset = rows?.[0] || null;
    if (!reset?.user_id) {
      return Response.json(
        { error: "Invalid or expired reset link" },
        { status: 400 },
      );
    }

    const userId = Number(reset.user_id);
    const hashedPassword = await hash(password);

    await sql.transaction((txn) => [
      // Update if exists
      txn(
        `
          UPDATE auth_accounts
          SET password = $1
          WHERE "userId" = $2
            AND provider = 'credentials'
            AND type = 'credentials'
        `,
        [hashedPassword, userId],
      ),
      // Insert if missing
      txn(
        `
          INSERT INTO auth_accounts (
            "userId",
            type,
            provider,
            "providerAccountId",
            password
          )
          SELECT $1, 'credentials', 'credentials', $2, $3
          WHERE NOT EXISTS (
            SELECT 1 FROM auth_accounts WHERE "userId" = $1 AND provider = 'credentials' AND type = 'credentials'
          )
        `,
        [userId, String(userId), hashedPassword],
      ),
      // Mark token used
      txn(
        `
          UPDATE password_reset_tokens
          SET used = true
